    { id: 'B', order: 2, loopsIdle: 0, loopsMsg: 0 },
    { id: 'C', order: 3, loopsIdle: -1, loopsMsg: 0 },
    { id: 'D', order: 4, loopsIdle: -1, loopsMsg: 0 },
