ops.find_block:
function playVid(index) {
    if (index === -1) return;

    const oldIndex = currentVidIndex;
    const currentConf = videoConfig.find(c => getVidIndexById(c.id) === index);
    if (currentConf) showToast(currentConf.id);

    if (oldIndex !== index) {
        currentLoopCount = 0;
        messageSentDuringVid = false;
    } else {
        currentLoopCount++;
    }

    currentVidIndex = index;
    vids[index].style.zIndex = '10';
    vids[index].style.opacity = '1';
    vids[index].currentTime = 0;

    const playPromise = vids[index].play();
    if (playPromise !== undefined) {
        playPromise.then(() => {
            // Only hide the old video AFTER the new one starts playing to prevent black flicker
            if (oldIndex !== index) {
                vids[oldIndex].pause();
                vids[oldIndex].style.opacity = '0';
            }
        }).catch(error => {
            console.log("Playback blocked, waiting for interaction");
        });
    }
}

